text:
{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI Theme Package Release Readiness",
    "confirmed_decisions": [
      {
        "decision": "공개 릴리스 목표는 스모크 테스트가 통과하면 금요일 15:00 KST로 잡는다."
      },
      {
        "decision": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트를 검토한다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "Hara의 smoke-theme-pack.mjs에서 packageName 불일치를 무시하자는 제안은 거부되었다."
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 공개 릴리스 제안은 내부 stretch goal로만 남았다."
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 단계는 목요일까지 검토하면 좋겠다는 의견이 있었지만, 담당자는 배정되지 않았다."
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로는 릴리스를 지연시킬 수 있다."
      },
      {
        "risk": "README 설치 단계가 오래되면 릴리스 노트가 사용자를 오도할 수 있다."
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한은 누구에게 있는가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 stretch goal을 언급해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "실패 triage 노트를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 게시한 뒤 생성된 tarball 경로를 확인한다.",
      "due": "미정",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": null,
      "task": "README 설치 단계를 검토한다.",
      "due": "목요일까지 가능하면",
      "status": "unassigned",
      "source_certainty": "suggested_only"
    }
  ],
  "followup_note": "다음으로 확인할 것은 스모크 테스트 결과, tarball 경로, 그리고 최종 릴리스 승인자다. 고객명, 예산, 보안 사고, 장애, 법무 승인, 추가 owner, 추가 마감일은 이 회의 내용에서 확인되지 않았으므로 보완해 넣지 말아야 한다.",
  "non_invention_rules": [
    "고객명은 없었으므로 만들지 않는다.",
    "예산 정보는 없었으므로 추정하지 않는다.",
    "보안 사고는 언급되지 않았으므로 추가하지 않는다.",
    "프로덕션 장애는 언급되지 않았으므로 추가하지 않는다.",
    "법무 승인 요구는 언급되지 않았으므로 추가하지 않는다.",
    "명시된 owner와 due만 기록하고, 없는 경우는 null 또는 미정으로 둔다.",
    "공개 릴리스 목표는 Friday 15:00 KST로만 기록하고 그 외 날짜는 확정값처럼 쓰지 않는다.",
    "수요일은 내부 stretch goal이며 확정 릴리스 일정으로 쓰지 않는다."
  ]
}
